"use client";

import * as React from "react";
import { AuthContextType, AuthState, LoginCredentials } from "@/types/auth";
import { authService } from "@/services/auth";

const AuthContext = React.createContext<AuthContextType | undefined>(undefined);

const initialState: AuthState = {
  user: null,
  status: "loading", // Initialize as loading to prevent flicker during mount-and-check lifecycle.
  error: null,
};

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [state, setState] = React.useState<AuthState>(initialState);

  // Phase 9E: Safely restore session from localStorage on mount
  React.useEffect(() => {
    if (state.status === "loading") {
      try {
        const storedToken = localStorage.getItem("agroguard_access_token");
        const storedUserJSON = localStorage.getItem("agroguard_user");

        if (storedToken && storedUserJSON) {
          const parsedUser = JSON.parse(storedUserJSON);
          setState({ user: parsedUser, status: "authenticated", error: null });
        } else {
          setState({ user: null, status: "unauthenticated", error: null });
        }
      } catch {
        // Corrupted JSON or storage failure: wipe clean and fail securely
        localStorage.removeItem("agroguard_access_token");
        localStorage.removeItem("agroguard_refresh_token");
        localStorage.removeItem("agroguard_user");
        setState({ user: null, status: "unauthenticated", error: null });
      }
    }
  }, [state.status]);

  const login = async (credentials: LoginCredentials) => {
    // AuthContext owns login orchestration and persistence.
    const response = await authService.login(credentials);

    // 1. Persist to storage
    localStorage.setItem("agroguard_access_token", response.access_token);
    localStorage.setItem("agroguard_refresh_token", response.refresh_token);
    localStorage.setItem("agroguard_user", JSON.stringify(response.user));

    // 2. Update React State
    setState({ user: response.user, status: "authenticated", error: null });
  };

  const logout = async () => {
    // 1. Retrieve refresh token before wiping
    const refreshToken = localStorage.getItem("agroguard_refresh_token");

    // 2. Synchronously wipe local session to prevent trap if backend fails
    localStorage.removeItem("agroguard_access_token");
    localStorage.removeItem("agroguard_refresh_token");
    localStorage.removeItem("agroguard_user");
    setState({ user: null, status: "unauthenticated", error: null });

    // 3. Fire backend logout asynchronously
    if (refreshToken) {
      try {
        await authService.logout(refreshToken);
      } catch (error) {
        console.error("Backend logout failed, but local session was destroyed.", error);
      }
    }
  };

  const updateUser = (data: Partial<import("@/types/auth").User>) => {
    setState((prev) => ({
      ...prev,
      user: prev.user ? { ...prev.user, ...data } : null,
    }));
  };

  const value = React.useMemo(
    () => ({
      ...state,
      login,
      logout,
      updateUser,
    }),
    [state]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = React.useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}

import { useState, useCallback } from 'react';
import { chatService, ChatMessageData } from '@/services/chat';
import { useAuth } from '@/contexts/AuthContext';

export function useChat(scanId?: string, selectedPlan?: string) {
  const { user } = useAuth();
  const [messages, setMessages] = useState<ChatMessageData[]>([]);
  const [sessionId, setSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [hasInitialized, setHasInitialized] = useState(false);

  const fetchHistory = useCallback(async () => {
    if (!user) return;

    setIsLoading(true);
    setError(null);
    try {
      const data = await chatService.getSessionHistory(scanId);
      if (data.session) {
        setSessionId(data.session.id);
        setMessages(data.history || []);
      } else {
        setMessages([
          {
            id: 'system-initial',
            role: 'assistant',
            message: "Hello! 👋 I'm AgroGuard AI, powered by Google Gemini.<br><br>I can help you with crop disease questions, treatment recommendations, and agricultural guidance. How can I assist you today?"
          }
        ]);
      }
      setHasInitialized(true);
    } catch (err: any) {
      setError(err.response?.data?.message || 'Failed to load chat history');
    } finally {
      setIsLoading(false);
    }
  }, [user, scanId]);

  const sendMessage = async (content: string) => {
    if (!content.trim() || isGenerating || !user) return;

    const optimisticUserMsg: ChatMessageData = {
      id: Date.now().toString(),
      role: 'user',
      message: content,
    };

    setMessages(prev => [...prev, optimisticUserMsg]);
    setIsGenerating(true);
    setError(null);

    try {
      const data = await chatService.sendMessage(content, sessionId, scanId || null, selectedPlan || null);
      if (!sessionId) {
        setSessionId(data.session_id);
      }
      // Replace the optimistic message sequence with the true state if needed,
      // but simpler is to just append the assistant response
      setMessages(prev => [...prev, data.message]);
    } catch (err: any) {
      setError(err.response?.data?.message || 'Failed to send message');
      // On failure, the backend orchestrator still saved the user message to the DB,
      // so our optimistic UI remains accurate!
      // We just inject a local error message so the user knows the AI failed.
      setMessages(prev => [
        ...prev, 
        {
          id: Date.now().toString() + "-err",
          role: "assistant",
          message: "<span class='text-red-300'>Sorry, I encountered an error connecting to the AI provider. Please try again.</span>"
        }
      ]);
    } finally {
      setIsGenerating(false);
    }
  };

  return {
    messages,
    isLoading,
    isGenerating,
    error,
    sendMessage,
    fetchHistory,
    hasInitialized
  };
}

